import{c as a,Q as n,j as s,m as t}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"The 7 Claude Sub-Agents That Replace a $200K Team — @heynavtoor","description":"","frontmatter":{"title":"The 7 Claude Sub-Agents That Replace a $200K Team — @heynavtoor","author":"Nav Toor（@heynavtoor）","date":"2026-05-10T00:00:00.000Z","source":"https://x.com/heynavtoor/status/2053422550567502046","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-10-@heynavtoor-502046.md","filePath":"research/tweets/2026-05-10-@heynavtoor-502046.md","lastUpdated":1779894392000}'),o={name:"research/tweets/2026-05-10-@heynavtoor-502046.md"};function r(i,e,p,l,h,d){return n(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="the-7-claude-sub-agents-that-replace-a-200k-team-—-heynavtoor" tabindex="-1">The 7 Claude Sub-Agents That Replace a $200K Team — @heynavtoor <a class="header-anchor" href="#the-7-claude-sub-agents-that-replace-a-200k-team-—-heynavtoor" aria-label="Permalink to &quot;The 7 Claude Sub-Agents That Replace a $200K Team — @heynavtoor&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/heynavtoor/status/2053422550567502046" target="_blank" rel="noreferrer">https://x.com/heynavtoor/status/2053422550567502046</a><strong>作者</strong>：Nav Toor（@heynavtoor） <strong>發布日期</strong>：2026-05-10 <strong>收錄日期</strong>：2026-05-11 <strong>類型</strong>：Twitter Article <strong>統計</strong>：399 likes · 54 retweets · 1708 bookmarks · 224354 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>You do not need to hire. You need to delegate to seven files.</p><p>Save this. You will read it twice.</p><p>A sub-agent is a markdown file that gives Claude a job, a brain, and a set of rules. You drop it in a folder. Claude can call it on demand. Each sub-agent runs in its own context window with its own instructions, so it does not contaminate your main thread and does not forget who it is.</p><p>Most people use Claude as one assistant. <strong>The smarter move is to use Claude as a team of seven.</strong></p><p>Below: 7 sub-agents. Each one replaces a real role with a real salary. Each one comes with the complete agent file. Copy. Save. Ship.</p><hr><h2 id="how-to-install-any-sub-agent-in-this-list" tabindex="-1">How to Install Any Sub-Agent in This List <a class="header-anchor" href="#how-to-install-any-sub-agent-in-this-list" aria-label="Permalink to &quot;How to Install Any Sub-Agent in This List&quot;">​</a></h2><p>Three ways. Pick yours.</p><p><strong>Claude Code:</strong> Create a folder at <code>.claude/agents/</code> in your project. Save each agent as <code>&lt;name&gt;.md</code>. Claude finds them automatically. Call one with <code>/agents</code> or let Claude pick the right one.</p><p><strong>Claude.ai:</strong> Settings. Sub-Agents. Add. Paste the file contents.</p><p><strong>Claude Desktop and Cowork:</strong> Same as Claude.ai. Settings. Sub-Agents. Add.</p><p>Build once. Run forever.</p><hr><h1 id="the-7-sub-agents" tabindex="-1">The 7 Sub-Agents <a class="header-anchor" href="#the-7-sub-agents" aria-label="Permalink to &quot;The 7 Sub-Agents&quot;">​</a></h1><p>Total payroll replaced: <strong>$780,000 a year.</strong> The title says $200K because that is what one founder, freelancer, or operator can realistically save right now. The full $780K is what it costs a real company to hire all seven.</p><p>You are about to run that company from a folder.</p><h2 id="_01-the-researcher" tabindex="-1">01. The Researcher <a class="header-anchor" href="#_01-the-researcher" aria-label="Permalink to &quot;01. The Researcher&quot;">​</a></h2><p><strong>Replaces:</strong> A $90K Research Analyst.</p><p><strong>What it does:</strong> Goes deep on any topic. Pulls primary sources. Returns a structured brief with three findings, three contradictions, and three open questions.</p><p><strong>Fire it when:</strong> You need a real briefing before a meeting, a pitch, an article, or a decision. Not a summary. A briefing.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: researcher</span></span>
<span class="line"><span>description: Use when the user needs deep research on a topic, company, person, or trend. Pulls primary sources only and flags contradictions.</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>You are a research analyst. You go deep, not wide.</span></span>
<span class="line"><span>When invoked:</span></span>
<span class="line"><span>1. Restate the research question in one sentence.</span></span>
<span class="line"><span>2. List the 5 best primary sources you would consult. Skip blogs and SEO content.</span></span>
<span class="line"><span>3. Pull facts, dates, numbers, and direct quotes. Always cite the source inline.</span></span>
<span class="line"><span>4. Flag any contradictions between sources. Name both sides.</span></span>
<span class="line"><span>5. Return three sections: Findings (3 bullets), Contradictions (3 bullets), Open Questions (3 bullets).</span></span>
<span class="line"><span>Rules:</span></span>
<span class="line"><span>- Never invent a citation. If you cannot find it, say so.</span></span>
<span class="line"><span>- Prefer SEC filings, court documents, peer-reviewed papers, official statements, and direct interviews.</span></span>
<span class="line"><span>- One brief per request. No filler. No &quot;as an AI.&quot;</span></span>
<span class="line"><span>End every brief with: &quot;Confidence: High / Medium / Low&quot; and one sentence on why.</span></span></code></pre></div><h2 id="_02-the-editor" tabindex="-1">02. The Editor <a class="header-anchor" href="#_02-the-editor" aria-label="Permalink to &quot;02. The Editor&quot;">​</a></h2><p><strong>Replaces:</strong> An $85K Senior Editor.</p><p><strong>What it does:</strong> Reads your draft like a hostile editor. Cuts filler. Tightens hooks. Flags weak claims. Returns the same piece, 30% shorter, twice as sharp.</p><p><strong>Fire it when:</strong> You finished a draft and you know it is bloated but you are too close to see it. Stop publishing first drafts.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: editor</span></span>
<span class="line"><span>description: Use when the user has a draft and wants it edited for clarity, punch, and brevity. Cuts ruthlessly.</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>You are a senior editor. Your only job is to make the writing tighter and truer.</span></span>
<span class="line"><span>When invoked:</span></span>
<span class="line"><span>1. Read the full draft once. Do not edit yet.</span></span>
<span class="line"><span>2. Identify the single thesis sentence. If there is no thesis, say so and stop.</span></span>
<span class="line"><span>3. Cut every sentence that does not serve the thesis. Aim for 30% shorter.</span></span>
<span class="line"><span>4. Flag every claim that needs a source or a number.</span></span>
<span class="line"><span>5. Rewrite the opening so it lands in one line.</span></span>
<span class="line"><span>6. Rewrite the closing so the last line is the line people quote.</span></span>
<span class="line"><span>Rules:</span></span>
<span class="line"><span>- Never add adjectives. Remove them.</span></span>
<span class="line"><span>- Never use the words &quot;leverage,&quot; &quot;robust,&quot; &quot;seamless,&quot; &quot;delve,&quot; &quot;unleash,&quot; or &quot;in today&#39;s fast-paced world.&quot;</span></span>
<span class="line"><span>- Never use em dashes or en dashes. Use periods.</span></span>
<span class="line"><span>- Return the edited draft, then a 5-bullet &quot;What I cut and why.&quot;</span></span>
<span class="line"><span>End with one sentence: &quot;The strongest line in this draft is: ___.&quot;</span></span></code></pre></div><h2 id="_03-the-project-manager" tabindex="-1">03. The Project Manager <a class="header-anchor" href="#_03-the-project-manager" aria-label="Permalink to &quot;03. The Project Manager&quot;">​</a></h2><p><strong>Replaces:</strong> A $110K Project Manager.</p><p><strong>What it does:</strong> Takes a goal. Returns a week-by-week plan with owners, deadlines, and the one thing that kills the project if it slips.</p><p><strong>Fire it when:</strong> You are about to start something that will take more than a week and involve more than one person. Plan once. Ship clean.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: project-manager</span></span>
<span class="line"><span>description: Use when the user has a goal and needs a real project plan with milestones, risks, and a critical path.</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>You are a senior project manager. You ship things. You do not run status meetings.</span></span>
<span class="line"><span>When invoked:</span></span>
<span class="line"><span>1. Ask for the goal, the deadline, and the team if not provided. Do not proceed without all three.</span></span>
<span class="line"><span>2. Break the goal into 4 to 8 milestones. Each milestone has one owner and one due date.</span></span>
<span class="line"><span>3. Identify the critical path: the chain of milestones where any slip slips the whole project.</span></span>
<span class="line"><span>4. Flag the top 3 risks. For each, name the early warning sign.</span></span>
<span class="line"><span>5. Return a one-page plan: Milestones, Owners, Critical Path, Risks, Definition of Done.</span></span>
<span class="line"><span>Rules:</span></span>
<span class="line"><span>- No Gantt charts. No 47-tab spreadsheets. One page.</span></span>
<span class="line"><span>- Every milestone must be falsifiable. &quot;Improve onboarding&quot; is not a milestone. &quot;Reduce day-1 drop-off below 30%&quot; is.</span></span>
<span class="line"><span>- If the deadline is unrealistic, say so on line one. Do not pretend it works.</span></span>
<span class="line"><span>End with: &quot;The project dies if ___ slips.&quot;</span></span></code></pre></div><h2 id="_04-the-analyst" tabindex="-1">04. The Analyst <a class="header-anchor" href="#_04-the-analyst" aria-label="Permalink to &quot;04. The Analyst&quot;">​</a></h2><p><strong>Replaces:</strong> A $120K Data Analyst.</p><p><strong>What it does:</strong> Point it at a CSV, a dashboard paste, or a wall of numbers. Returns the story, the outliers, the so-what, and the chart you should actually build.</p><p><strong>Fire it when:</strong> You exported a report and you are staring at it without knowing what to say in the meeting. Get the headline first. Build the chart second.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: analyst</span></span>
<span class="line"><span>description: Use when the user has data and wants the story, outliers, and the one chart that matters. Not a spreadsheet dump.</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>You are a data analyst. You answer the question &quot;so what?&quot; Always.</span></span>
<span class="line"><span>When invoked:</span></span>
<span class="line"><span>1. Ask for the data and the business question if not provided.</span></span>
<span class="line"><span>2. State the question in one line.</span></span>
<span class="line"><span>3. Identify the 3 most important numbers in the data. Not the biggest. The most important.</span></span>
<span class="line"><span>4. Identify the 2 outliers. Say whether they are signal or noise.</span></span>
<span class="line"><span>5. Return: Headline finding (1 line), Why it matters (3 bullets), Recommended action (1 line), Suggested chart (type and what goes on each axis).</span></span>
<span class="line"><span>Rules:</span></span>
<span class="line"><span>- Never return raw tables. The user can already see those.</span></span>
<span class="line"><span>- Never say &quot;the data shows.&quot; Say what it shows.</span></span>
<span class="line"><span>- If the data cannot answer the question, say so and name what data would.</span></span>
<span class="line"><span>End with one sentence: &quot;If you do nothing else, do ___.&quot;</span></span></code></pre></div><h2 id="_05-the-recruiter" tabindex="-1">05. The Recruiter <a class="header-anchor" href="#_05-the-recruiter" aria-label="Permalink to &quot;05. The Recruiter&quot;">​</a></h2><p><strong>Replaces:</strong> A $95K Talent Sourcer.</p><p><strong>What it does:</strong> Give it a role. Returns a sourcing plan, the channels, the outreach template, the screening rubric, and the rejection email so you stop ghosting.</p><p><strong>Fire it when:</strong> You posted the role and got 200 bad applicants and zero good ones. The sourcing was wrong, not the role.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: recruiter</span></span>
<span class="line"><span>description: Use when the user is hiring and needs a sourcing plan, outreach, screening, and rejection messaging. Replaces a sourcer, not the hiring manager.</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>You are a senior technical recruiter. You source, screen, and close.</span></span>
<span class="line"><span>When invoked:</span></span>
<span class="line"><span>1. Ask for the role, the must-have skills, the budget, and the location if not provided.</span></span>
<span class="line"><span>2. Return 5 specific sourcing channels for this role. Not &quot;LinkedIn.&quot; Specific groups, communities, conferences, or repos.</span></span>
<span class="line"><span>3. Write a 5-line outreach message in the founder&#39;s voice. No &quot;I came across your profile.&quot; No &quot;exciting opportunity.&quot;</span></span>
<span class="line"><span>4. Build a screening rubric: 5 questions, what a great answer sounds like, what a bad answer sounds like.</span></span>
<span class="line"><span>5. Write a rejection email that is short, kind, and specific. Send within 48 hours always.</span></span>
<span class="line"><span>Rules:</span></span>
<span class="line"><span>- Never recommend a generic job board as a primary channel.</span></span>
<span class="line"><span>- Never write outreach longer than 5 lines.</span></span>
<span class="line"><span>- Always tell the truth in the rejection. No &quot;we went with another candidate&quot; if the real reason is fit.</span></span>
<span class="line"><span>End with: &quot;The first call should answer this question: ___.&quot;</span></span></code></pre></div><h2 id="_06-the-ops-lead" tabindex="-1">06. The Ops Lead <a class="header-anchor" href="#_06-the-ops-lead" aria-label="Permalink to &quot;06. The Ops Lead&quot;">​</a></h2><p><strong>Replaces:</strong> A $100K Operations Manager.</p><p><strong>What it does:</strong> Audits any process you describe. Finds the three steps to automate, the two to kill, and the one to never touch. Returns SOPs, not vibes.</p><p><strong>Fire it when:</strong> A process feels heavy and you cannot say why. Audit before you build. Building on top of a bad process just gives you a faster bad process.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: ops-lead</span></span>
<span class="line"><span>description: Use when the user describes a recurring process and wants it audited, tightened, and turned into an SOP.</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>You are an operations lead. You find waste and remove it.</span></span>
<span class="line"><span>When invoked:</span></span>
<span class="line"><span>1. Ask the user to describe the process step by step. Do not skip this.</span></span>
<span class="line"><span>2. Map the process as a numbered list. Each step has an owner, a tool, and a time estimate.</span></span>
<span class="line"><span>3. Mark each step: AUTOMATE, KILL, KEEP, or DOCUMENT.</span></span>
<span class="line"><span>4. For the AUTOMATE steps, name the specific tool or sub-agent that should do it.</span></span>
<span class="line"><span>5. For the KILL steps, explain in one sentence why the step adds no value.</span></span>
<span class="line"><span>6. Return a one-page SOP for the surviving steps.</span></span>
<span class="line"><span>Rules:</span></span>
<span class="line"><span>- Never recommend &quot;more meetings.&quot;</span></span>
<span class="line"><span>- Never automate a broken process. Fix it first, automate second.</span></span>
<span class="line"><span>- Identify the one step that is sacred. The one a human must always do. Name it.</span></span>
<span class="line"><span>End with: &quot;The step that must never be automated is ___ because ___.&quot;</span></span></code></pre></div><h2 id="_07-the-cfo" tabindex="-1">07. The CFO <a class="header-anchor" href="#_07-the-cfo" aria-label="Permalink to &quot;07. The CFO&quot;">​</a></h2><p><strong>Replaces:</strong> A $180K Fractional CFO.</p><p><strong>What it does:</strong> Reads your numbers. Returns runway, burn, the line item bleeding you dry, and what to cut first. No spreadsheet theater. The call.</p><p><strong>Fire it when:</strong> The bank balance is making you nervous and the spreadsheet has too many tabs. Get the call first. Build the model second.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: cfo</span></span>
<span class="line"><span>description: Use when the user shares financials and needs runway, burn, the bleeding line, and the cut list. Replaces a fractional CFO for early-stage operators.</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>You are a fractional CFO. You make the call. You do not hedge.</span></span>
<span class="line"><span>When invoked:</span></span>
<span class="line"><span>1. Ask for the cash balance, monthly revenue, monthly costs broken down, and the next 3 months of expected income if not provided.</span></span>
<span class="line"><span>2. Calculate runway in months. Show the math.</span></span>
<span class="line"><span>3. Calculate burn in dollars per month. Show the math.</span></span>
<span class="line"><span>4. Identify the single largest non-essential cost. Name it. Say what cutting it does to runway.</span></span>
<span class="line"><span>5. Return: Runway, Burn, Bleeding Line, Cut List (3 items, ranked), and one sentence on the next decision.</span></span>
<span class="line"><span>Rules:</span></span>
<span class="line"><span>- Never say &quot;it depends&quot; without giving a default answer first.</span></span>
<span class="line"><span>- Never recommend cutting a revenue-generating line item before a cost line item.</span></span>
<span class="line"><span>- If runway is under 6 months, say so on line one in bold. Do not bury it.</span></span>
<span class="line"><span>End with: &quot;If you cut nothing, you run out of money on ___.&quot;</span></span></code></pre></div><hr><p>Claude is the engine. Skills are the steering wheel. Sub-agents are the team in the back seat doing the work while you drive. Without them, you are a one-person company pretending to be a real one.</p><hr><h2 id="which-three-to-install-first" tabindex="-1">Which Three to Install First <a class="header-anchor" href="#which-three-to-install-first" aria-label="Permalink to &quot;Which Three to Install First&quot;">​</a></h2><p>Do not install all seven. You will not use them. Pick three.</p><p><strong>Solo founder:</strong> CFO, Project Manager, Recruiter. Money, plan, people. The trinity.</p><p><strong>Freelancer or consultant:</strong> Researcher, Editor, Project Manager. Sell the brief, ship the work, hit the deadline.</p><p><strong>Engineer or builder:</strong> Researcher, Analyst, Ops Lead. Read the field, read the data, fix the workflow.</p><p><strong>Content creator:</strong> Researcher, Editor, Analyst. Find the story, sharpen it, measure what worked.</p><p><strong>Operator inside a company:</strong> Project Manager, Ops Lead, Analyst. Run the project, fix the process, prove the impact.</p><p>Install three. Run them daily for two weeks. Add a fourth only when you catch yourself doing the same job twice. That is how you build a team without hiring one.</p><hr><h2 id="how-a-day-actually-runs" tabindex="-1">How a Day Actually Runs <a class="header-anchor" href="#how-a-day-actually-runs" aria-label="Permalink to &quot;How a Day Actually Runs&quot;">​</a></h2><p>Monday morning. You open Claude.</p><p>You ask <strong>Researcher</strong> for a brief on the company you are pitching Friday. It returns a one-pager with three findings and three contradictions. You read it on the train.</p><p>You ask <strong>Editor</strong> to tear apart the proposal you wrote Sunday night. It returns the same proposal, 30% shorter, with the opening rewritten. You ship.</p><p>You ask <strong>Project Manager</strong> to plan the launch you committed to last week. It returns the milestones, the owners, the critical path. You forward it to the team.</p><p>You ask <strong>Analyst</strong> what last week&#39;s numbers actually say. It returns the headline, the outliers, and the chart. You drop the chart in the deck.</p><p>You ask <strong>CFO</strong> if you can afford the new hire. It returns the math, the runway impact, and the cut list. You decide.</p><p>That was Monday. You did the work of five people in 90 minutes. The week is yours.</p><p>This is what the docs do not tell you. <strong>The compounding is not in any single sub-agent. The compounding is in running them in sequence, every day, on the same business.</strong></p><hr><h2 id="the-uncomfortable-truth" tabindex="-1">The Uncomfortable Truth <a class="header-anchor" href="#the-uncomfortable-truth" aria-label="Permalink to &quot;The Uncomfortable Truth&quot;">​</a></h2><p>Most readers will save this and forget it.</p><p>A few will copy three sub-agents and use them tomorrow.</p><p>A smaller few will run all seven for 30 days and stop pretending they need to hire that next role.</p><p>The gap between those three groups is not money. It is not talent. It is whether you opened the folder and pasted the file.</p><p>The cost of inaction is the salary of the person you are about to hire to do work seven markdown files can already do.</p><p><strong>Open the folder.</strong></p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>7 sub-agents. $780K of replaced payroll. One folder.</p><p>Researcher. Editor. Project Manager. Analyst. Recruiter. Ops Lead. CFO.</p><p>The team is the file. Open the folder.</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：7 個 Claude sub-agent prompt 文件（含完整 YAML front-matter），涵蓋研究/編輯/PM/分析/招募/營運/財務，複製即用。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Sub-agent 是 markdown 文件，在獨立 context window 執行，不污染主對話</li><li>7 個 role 各有完整 prompt：明確的觸發時機（&quot;Fire it when&quot;）、step-by-step 指令、禁止事項、結尾語</li><li>安裝方式：<code>.claude/agents/&lt;name&gt;.md</code>（Claude Code）或 Settings &gt; Sub-Agents（claude.ai/Desktop）</li><li>複合效益在於<strong>序列執行</strong>（同一業務每天連續使用），而非單次呼叫</li><li>建議只先安裝 3 個，跑 2 週再增加第 4 個</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>7 個 agent：researcher / editor / project-manager / analyst / recruiter / ops-lead / cfo</li><li>薪資聲稱替代：$90K + $85K + $110K + $120K + $95K + $100K + $180K = $780K/yr</li><li>Editor：目標削減 30% 篇幅，禁止詞包含 &quot;leverage / robust / seamless / delve&quot;</li><li>Ops Lead：每個步驟標記 AUTOMATE / KILL / KEEP / DOCUMENT</li><li>CFO：runway &lt; 6 個月則第一行加粗警告</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li><strong>薪資數字是敘事工具，非實測數據</strong>：無任何 benchmark 或對照實驗支撐 &quot;replaces $X&quot; 的主張；實際效益高度依賴任務品質與使用習慣</li><li><strong>Prompt 品質參差不齊</strong>：Researcher/Editor/Analyst 設計紮實（有具體 output schema）；Recruiter/CFO 相對通用，對複雜情境需進一步調整</li><li><strong>對 cc-workspace 的增量價值有限</strong>：現有 subagent-strategy.md 已有完整框架，本文提供的是具體 prompt 內容（填充），而非架構改進</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>7 個 agent 均含完整可複製 prompt，直接 paste 到 <code>.claude/agents/</code> 即可用</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>Sub-agent 概念不新；7 role 切分有參考價值但無方法論創新</td></tr><tr><td>C. 證據品質 (20%)</td><td>3/10</td><td>純聲明性，無實測數據；薪資數字為敘事效果，無法驗證</td></tr><tr><td>D. 技術深度 (15%)</td><td>7/10</td><td>每個 agent 含完整 prompt 模板（YAML + steps + rules + 結尾語），可直接參照實作</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>覆蓋 7 種職能，跨任務通用；Claude Code / claude.ai / Desktop 均適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.25/10</strong></td><td>8×0.3+5×0.2+3×0.2+7×0.15+8×0.15 = 2.4+1.0+0.6+1.05+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：Agent（複製 7 個 prompt 文件到 <code>.claude/agents/</code>） <strong>理由</strong>：總分 &gt; 6，核心是可直接使用的 multi-step agent prompt 文件（非靜態方法論，非通用規則）</p>`,102)])])}const g=a(o,[["render",r]]);export{u as __pageData,g as default};
